#[async_trait]
impl<R: SecurityEventProjectionRepository> SecurityEventEventHandler for SecurityEventProjector<R> {

    async fn on_created(&self, event: SecurityEventCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = SecurityEventProjection::new(
            event.id,
            event.user_id,
            event.session_id,
            event.event_type,
            event.severity,
            event.ip_address,
            event.user_agent,
            event.description,
            event.details,
            event.resolved,
            event.resolved_at,
            event.resolved_by_user_id,
            event.resolution_notes,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: SecurityEventUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.session_id = event.session_id;
            projection.event_type = event.event_type;
            projection.severity = event.severity;
            projection.ip_address = event.ip_address;
            projection.user_agent = event.user_agent;
            projection.description = event.description;
            projection.details = event.details;
            projection.resolved = event.resolved;
            projection.resolved_at = event.resolved_at;
            projection.resolved_by_user_id = event.resolved_by_user_id;
            projection.resolution_notes = event.resolution_notes;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: SecurityEventDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

